class Solution:
    def minCostSetTime(self, startAt, moveCost, pushCost, targetSeconds):
        best = None
        for m in range(100):
            s = targetSeconds - m * 60
            if 0 <= s <= 99:
                digits = '%02d%02d' % (m, s)
                i = 0
                while i < len(digits) - 1 and digits[i] == '0':
                    i += 1
                digits = digits[i:]
                cost = 0
                cur = startAt
                for ch in digits:
                    d = int(ch)
                    if d != cur:
                        cost += moveCost
                    cost += pushCost
                    cur = d
                if best is None or cost < best:
                    best = cost
        return best

