class Solution:
    def minCostSetTime(self, startAt, moveCost, pushCost, targetSeconds):
        candidates = []
        m1, s1 = divmod(targetSeconds, 60)
        if m1 <= 99:
            candidates.append((m1, s1))
        if m1 >= 1 and s1 <= 39:
            candidates.append((m1 - 1, s1 + 60))
        best = None
        for m, s in candidates:
            digits = ('%02d%02d' % (m, s)).lstrip('0') or '0'
            cost = 0
            cur = startAt
            for ch in digits:
                d = int(ch)
                if d != cur:
                    cost += moveCost
                cost += pushCost
                cur = d
            if best is None or cost < best:
                best = cost
        return best

