var minCostSetTime = function(startAt, moveCost, pushCost, targetSeconds) {
    const candidates = [];
    const m1 = Math.floor(targetSeconds / 60);
    const s1 = targetSeconds % 60;
    if (m1 <= 99) candidates.push([m1, s1]);
    if (m1 >= 1 && s1 <= 39) candidates.push([m1 - 1, s1 + 60]);
    let best = Infinity;
    for (const [m, s] of candidates) {
        let digits = String(m).padStart(2, '0') + String(s).padStart(2, '0');
        digits = digits.replace(/^0+(?=.)/, '');
        let cost = 0;
        let cur = startAt;
        for (const ch of digits) {
            const d = Number(ch);
            if (d !== cur) cost += moveCost;
            cost += pushCost;
            cur = d;
        }
        best = Math.min(best, cost);
    }
    return best;
};
